# ─────────────────────────────────────────────
# AUDIO SYNTHESIS
# ─────────────────────────────────────────────
def make_tone(freq, duration, sr=SAMPLE_RATE, amplitude=0.18):
    t = np.linspace(0, duration, int(sr * duration), endpoint=False)
    # Rich harmonic content
    wave = (amplitude * np.sin(2 * np.pi * freq * t) +
            amplitude * 0.5 * np.sin(2 * np.pi * freq * 2 * t) +
            amplitude * 0.25 * np.sin(2 * np.pi * freq * 3 * t) +
            amplitude * 0.1 * np.sin(2 * np.pi * freq * 4 * t))
    # Envelope
    env = np.ones(len(t))
    fade = min(FADE_SAMPLES, len(t) // 4)
    env[:fade] = np.linspace(0, 1, fade)
    env[-fade:] = np.linspace(1, 0, fade)
    return wave * env

def play_sequence(tempo_factor=1.0, solo_voice=None, stop_event=None):
    """Play the 5-note motif with all 4 voices harmonized."""
    dur = NOTE_DURATION / tempo_factor
    for note_idx in range(5):
        if stop_event and stop_event.is_set():
            break
        freqs = VOICINGS[note_idx]
        combined = np.zeros(int(SAMPLE_RATE * dur))
        for v_idx, freq in enumerate(freqs):
            if solo_voice is not None and v_idx != solo_voice:
                amp = 0.04  # ghost
            else:
                amp = 0.18
            combined += make_tone(freq, dur, amplitude=amp)
        combined = np.clip(combined, -1.0, 1.0)
        sd.play(combined, SAMPLE_RATE)
        sd.wait()
    # Final convergence chord
    if not (stop_event and stop_event.is_set()):
        chord = np.zeros(int(SAMPLE_RATE * 2.0))
        for v_idx, freq in enumerate(VOICINGS[4]):
            chord += make_tone(freq, 2.0, amplitude=0.22)
        chord = np.clip(chord, -1.0, 1.0)
        sd.play(chord, SAMPLE_RATE)
        sd.wait()

