# ─────────────────────────────────────────────
# ANIMATION HELPERS
# ─────────────────────────────────────────────
def get_current_note_index():
    """Determine which note is currently playing based on elapsed time."""
    if not state['playing'] or state['start_time'] is None:
        return -1
    elapsed = time.time() - state['start_time']
    dur = NOTE_DURATION / max(state['tempo'], 0.01)
    idx = int(elapsed / dur)
    if idx >= 5:
        return 5  # convergence phase
    return idx

def update_stars(angle):
    """Parallax star rotation."""
    cx, cy = 7.0, 4.5
    cos_a = np.cos(angle * 0.001)
    sin_a = np.sin(angle * 0.001)
    sx = star_x - cx
    sy = star_y - cy
    rx = sx * cos_a - sy * sin_a + cx
    ry = sx * sin_a + sy * cos_a + cy
    offsets = np.column_stack([rx, ry])
    star_scatter.set_offsets(offsets)

def make_ribbon_wave(v_idx, note_idx, phase, intensity, solo_voice):
    """Generate bioluminescent waveform for a voice ribbon."""
    y_base = RIBBON_Y[v_idx]
    x = x_ribbon

    if note_idx < 0 or note_idx >= 5:
        # Idle gentle drift
        wave = 0.04 * np.sin(2 * np.pi * x / 3.0 + phase * 0.5 + v_idx)
        return y_base + wave

    # Active: pulsing wave based on voice frequency
    freq_ratio = VOICINGS[note_idx][v_idx] / 200.0
    amp = 0.18 * intensity
    if solo_voice is not None and v_idx != solo_voice:
        amp *= 0.15

    # Multi-frequency wave for richness
    wave = (amp * np.sin(2 * np.pi * freq_ratio * x / 14.0 * 8 + phase * 3) +
            amp * 0.4 * np.sin(2 * np.pi * freq_ratio * x / 14.0 * 16 + phase * 5) +
            amp * 0.2 * np.sin(2 * np.pi * x / 2.0 + phase * 1.5 + v_idx * 0.7))
    return y_base + wave

# ─────────────────────────────────────────────
# MAIN ANIMATION FUNCTION
# ─────────────────────────────────────────────
frame_count = [0]

def animate(frame):
    frame_count[0] += 1
    t = frame_count[0] * 0.04  # ~25fps
    state['phase'] = t
    state['star_angle'] += 1.0

    # Update tempo from slider
    state['tempo'] = tempo_slider.val

    # Determine current note
    note_idx = get_current_note_index()
    state['current_note'] = note_idx

    # ── Stars ──
    if state['playing']:
        update_stars(state['star_angle'])

    # ── Note orbs ──
    for i in range(5):
        is_active = (note_idx == i)
        is_hovered = (state['hovered_note'] == i)

        pulse = 1.0 + 0.3 * np.sin(t * 4 + i) if is_active else 1.0
        glow_alpha = 0.35 * pulse if is_active else (0.15 if is_hovered else 0.06)
        orb_alpha = 1.0 if is_active else (0.7 if is_hovered else 0.45)

        orb_glows[i].set_radius(orb_radius * 2.2 * pulse)
        orb_glows[i].set_alpha(glow_alpha)
        orb_circles[i].set_alpha(orb_alpha)
        orb_circles[i].set_radius(orb_radius * (1.0 + 0.1 * pulse if is_active else 1.0))

        # Orb drift
        drift_y = orb_y[i] + 0.05 * np.sin(t * 0.8 + i * 1.2)
        orb_circles[i].center = (orb_x[i], drift_y)
        orb_glows[i].center = (orb_x[i], drift_y)
        orb_labels[i].set_y(drift_y - 0.65)

    # ── Harmonic beams ──
    for i in range(5):
        is_active = (note_idx == i)
        if is_active:
            state['beam_alpha'][i] = min(state['beam_alpha'][i] + 0.12, 0.55)
        else:
            state['beam_alpha'][i] = max(state['beam_alpha'][i] - 0.04, 0.0)

        ba = state['beam_alpha'][i]
        beam_patches[i].set_alpha(ba)
        # Bloom effect: vary linewidth
        lw = 18 + 12 * np.sin(t * 6) if is_active else 18
        beam_patches[i].set_linewidth(lw * ba + 1)

    # ── Voice ribbons ──
    for v in range(4):
        intensity = 1.0
        if note_idx >= 0 and note_idx < 5:
            intensity = 1.0 + 0.5 * np.sin(t * 5 + v)
        else:
            intensity = 0.3

        y_wave = make_ribbon_wave(v, note_idx, t, intensity, state['solo_voice'])
        ribbon_lines[v].set_ydata(y_wave)

        # Alpha based on solo
        if state['solo_voice'] is not None:
            if v == state['solo_voice']:
                ribbon_lines[v].set_alpha(1.0)
                ribbon_lines[v].set_linewidth(2.5)
            else:
                ribbon_lines[v].set_alpha(0.15)
                ribbon_lines[v].set_linewidth(1.0)
        else:
            alpha = 0.85 if (note_idx >= 0 and note_idx < 5) else 0.4
            ribbon_lines[v].set_alpha(alpha)
            ribbon_lines[v].set_linewidth(1.8)

    # ── Convergence effect ──
    if note_idx == 5:  # After all 5 notes
        state['convergence'] = min(state['convergence'] + 0.03, 1.0)
    else:
        state['convergence'] = max(state['convergence'] - 0.02, 0.0)

    conv = state['convergence']
    if conv > 0:
        # Flash
        flash_r = conv * 0.8
        flash_a = max(0, 0.9 - conv * 1.5)
        convergence_flash.set_radius(flash_r)
        convergence_flash.set_alpha(flash_a)

        # Ripple
        rip_r = conv * 6.0
        rip_a = max(0, 0.7 * (1.0 - conv))
        ripple_circle.set_radius(rip_r)
        ripple_circle.set_alpha(rip_a)
        ripple_circle.set_linewidth(max(0.5, 3 * (1 - conv)))
    else:
        convergence_flash.set_alpha(0)
        ripple_circle.set_alpha(0)

    # ── Title pulse ──
    title_alpha = 0.7 + 0.3 * np.sin(t * 0.5)
    title_txt.set_alpha(title_alpha)

    # ── Play button text ──
    if state['playing']:
        play_btn_txt.set_text('[ STOP ]')
        play_btn_txt.set_color('#FF4444')
    else:
        play_btn_txt.set_text('[ PLAY ]')
        play_btn_txt.set_color('#00FF88')

    return (ribbon_lines + orb_circles + orb_glows + beam_patches +
            [ripple_circle, convergence_flash, title_txt, star_scatter,
             play_btn_txt] + orb_labels)

# ─────────────────────────────────────────────
# EVENT HANDLERS
# ─────────────────────────────────────────────
def start_playback():
    state['stop_event'].clear()
    state['start_time'] = time.time()
    state['convergence'] = 0.0
    state['beam_alpha'] = [0.0] * 5

    def audio_worker():
        play_sequence(
            tempo_factor=state['tempo'],
            solo_voice=state['solo_voice'],
            stop_event=state['stop_event']
        )
        state['playing'] = False
        state['current_note'] = -1

    state['audio_thread'] = threading.Thread(target=audio_worker, daemon=True)
    state['audio_thread'].start()

def stop_playback():
    state['stop_event'].set()
    sd.stop()
    state['playing'] = False
    state['current_note'] = -1
    state['start_time'] = None

def on_click(event):
    if event.inaxes == play_btn_ax:
        if state['playing']:
            stop_playback()
        else:
            state['playing'] = True
            start_playback()
        return

    if event.inaxes != ax_main:
        return

    # Check orb clicks for solo
    mx, my = event.xdata, event.ydata
    if mx is None or my is None:
        return
    for i in range(5):
        dist = np.sqrt((mx - orb_x[i])**2 + (my - orb_y[i])**2)
        if dist < orb_radius * 1.5:
            # Toggle solo for corresponding voice (map note -> voice concept)
            v = i % 4
            if state['solo_voice'] == v:
                state['solo_voice'] = None
                print(f"Solo cleared")
            else:
                state['solo_voice'] = v
                print(f"Solo: {VOICE_NAMES[v]}")
            return

def on_motion(event):
    if event.inaxes != ax_main:
        state['hovered_note'] = None
        return
    mx, my = event.xdata, event.ydata
    if mx is None or my is None:
        return
    state['hovered_note'] = None
    for i in range(5):
        dist = np.sqrt((mx - orb_x[i])**2 + (my - orb_y[i])**2)
        if dist < orb_radius * 2.0:
            state['hovered_note'] = i
            break

def on_key(event):
    if event.key == ' ':
        if state['playing']:
            stop_playback()
        else:
            state['playing'] = True
            start_playback()

fig.canvas.mpl_connect('button_press_event', on_click)
fig.canvas.mpl_connect('motion_notify_event', on_motion)
fig.canvas.mpl_connect('key_press_event', on_key)

